import torch
import torch.nn as nn
import torch.nn.functional as F
from torch.utils.cpp_extension import load_inline
import math

# Define custom CUDA kernel for optimized ConvTranspose1d
conv_transpose1d_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <ATen/ATen.h>

template<typename scalar_t>
__global__ void conv_transpose1d_kernel(
    const scalar_t* __restrict__ input,
    const scalar_t* __restrict__ weight,
    scalar_t* __restrict__ output,
    const int batch_size,
    const int in_channels,
    const int out_channels,
    const int input_length,
    const int kernel_size,
    const int stride,
    const int padding,
    const int dilation,
    const int output_length,
    const scalar_t* __restrict__ bias_data) {

    // Calculate global thread index
    const int tid = blockIdx.x * blockDim.x + threadIdx.x;
    const int total_elements = batch_size * out_channels * output_length;

    if (tid >= total_elements) {
        return;
    }

    // Decompose thread index into batch, channel, and position
    const int batch = tid / (out_channels * output_length);
    const int channel = (tid % (out_channels * output_length)) / output_length;
    const int out_idx = tid % output_length;

    scalar_t result = 0.0;

    // For each input channel
    for (int in_ch = 0; in_ch < in_channels; ++in_ch) {
        // For each kernel position
        for (int k = 0; k < kernel_size; ++k) {
            // Calculate input position for transposed convolution
            int input_pos = out_idx - k * dilation + padding;

            // Check if this kernel position contributes
            if (input_pos >= 0 && input_pos < input_length * stride && input_pos % stride == 0) {
                int input_idx = input_pos / stride;

                // Weight index: [in_ch, channel, k]
                int weight_idx = in_ch * (out_channels * kernel_size) + channel * kernel_size + k;

                // Input index: [batch, in_ch, input_idx]
                int input_offset = batch * (in_channels * input_length) + in_ch * input_length + input_idx;

                result += input[input_offset] * weight[weight_idx];
            }
        }
    }

    // Add bias if present
    if (bias_data != nullptr) {
        result += bias_data[channel];
    }

    // Write output
    int output_offset = batch * (out_channels * output_length) + channel * output_length + out_idx;
    output[output_offset] = result;
}

torch::Tensor conv_transpose1d_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias,
    int stride,
    int padding,
    int dilation) {

    // Get tensor dimensions
    auto batch_size = input.size(0);
    auto in_channels = input.size(1);
    auto input_length = input.size(2);
    auto out_channels = weight.size(1);
    auto kernel_size = weight.size(2);

    // Calculate output length
    int output_length = (input_length - 1) * stride - 2 * padding + dilation * (kernel_size - 1) + 1;

    // Create output tensor
    auto output = torch::zeros({batch_size, out_channels, output_length}, 
                              torch::TensorOptions()
                              .device(input.device())
                              .dtype(input.dtype()));

    // Check if bias is defined
    bool has_bias = bias.defined() && bias.numel() > 0;

    // Calculate total number of threads needed
    int total_elements = batch_size * out_channels * output_length;
    const int threads_per_block = 256;
    int num_blocks = (total_elements + threads_per_block - 1) / threads_per_block;

    // Launch kernel based on data type
    AT_DISPATCH_FLOATING_TYPES_AND_HALF(
        input.scalar_type(), 
        "conv_transpose1d_cuda", 
        ([&] {
            conv_transpose1d_kernel<scalar_t><<<num_blocks, threads_per_block>>>(
                input.data_ptr<scalar_t>(),
                weight.data_ptr<scalar_t>(),
                output.data_ptr<scalar_t>(),
                batch_size,
                in_channels,
                out_channels,
                input_length,
                kernel_size,
                stride,
                padding,
                dilation,
                output_length,
                has_bias ? bias.data_ptr<scalar_t>() : nullptr
            );
        })
    );

    // Check for CUDA errors
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        throw std::runtime_error(cudaGetErrorString(err));
    }

    return output;
}
"""

conv_transpose1d_cpp_source = """
torch::Tensor conv_transpose1d_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias,
    int stride,
    int padding,
    int dilation);
"""

# Compile the inline CUDA code
conv_transpose1d_op = load_inline(
    name="conv_transpose1d",
    cpp_sources=conv_transpose1d_cpp_source,
    cuda_sources=conv_transpose1d_source,
    functions=["conv_transpose1d_cuda"],
    verbose=False,
    extra_cflags=["-O3"],
    extra_ldflags=[],
    with_cuda=True,
    extra_include_paths=[]
)

class ModelNew(nn.Module):
    """
    Optimized ConvTranspose1d with custom CUDA kernel.
    """
    def __init__(self, in_channels: int, out_channels: int, kernel_size: int, 
                 stride: int = 1, padding: int = 0, dilation: int = 1, bias: bool = False):
        super(ModelNew, self).__init__()

        self.in_channels = in_channels
        self.out_channels = out_channels
        self.kernel_size = kernel_size
        self.stride = stride
        self.padding = padding
        self.dilation = dilation

        # Initialize weight parameters with correct shape
        # PyTorch ConvTranspose1d weight shape: [in_channels, out_channels, kernel_size]
        self.weight = nn.Parameter(torch.empty(
            in_channels, out_channels, kernel_size
        ))

        if bias:
            self.bias = nn.Parameter(torch.empty(out_channels))
        else:
            self.register_parameter('bias', None)

        # Initialize parameters
        self.reset_parameters()

    def reset_parameters(self):
        # Kaiming uniform initialization
        nn.init.kaiming_uniform_(self.weight, a=math.sqrt(5))
        if self.bias is not None:
            fan_in, _ = nn.init._calculate_fan_in_and_fan_out(self.weight)
            bound = 1 / math.sqrt(fan_in) if fan_in > 0 else 0
            nn.init.uniform_(self.bias, -bound, bound)

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        # Use custom CUDA kernel if on GPU
        if x.is_cuda:
            # Prepare bias tensor
            bias_tensor = self.bias if self.bias is not None else torch.tensor([], device=x.device, dtype=x.dtype)

            # Call custom CUDA kernel
            return conv_transpose1d_op.conv_transpose1d_cuda(
                x, 
                self.weight, 
                bias_tensor,
                self.stride,
                self.padding,
                self.dilation
            )
        else:
            # Fallback to PyTorch implementation for CPU
            return F.conv_transpose1d(
                x, self.weight, self.bias, 
                stride=self.stride, 
                padding=self.padding,
                dilation=self.dilation
            )

    def extra_repr(self):
        return (f'in_channels={self.in_channels}, out_channels={self.out_channels}, '
                f'kernel_size={self.kernel_size}, stride={self.stride}, '
                f'padding={self.padding}, dilation={self.dilation}, '
                f'bias={self.bias is not None}')

